import React, { useState } from "react";
import axios from "axios";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const login = async (email, password) => {
    try {
      const res = await axios.post("http://localhost:5000/api/auth/login", {
        email,
        password,
      });
      localStorage.setItem("token", res.data.token);
      // After storing token, you can fetch transactions
      fetchTransactions();
    } catch {
      setError("Login failed. Check your credentials.");
    }
  };

  // New function to fetch transactions using stored token
  const fetchTransactions = async () => {
    const token = localStorage.getItem("token");
    axios.get("${API_BASE}/transactions", {
      headers: { Authorization: "Bearer ${token}" },
    });
    if (!token) {
      setError("No token found. Please login first.");
      return;
    }
    try {
      const res = await axios.get("http://localhost:5000/api/transactions", {
        headers: { Authorization: `Bearer ${token}` },
      });
      console.log("Transactions:", res.data);
      // Handle/display transactions data as needed
    } catch {
      setError("Failed to fetch transactions.");
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    login(email, password);
  };

  return (
    <div
      style={{
        background: "#EAEFF9",
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <form
        onSubmit={handleSubmit}
        style={{
          background: "#fff",
          padding: "2.5rem",
          borderRadius: 18,
          boxShadow: "0 4px 16px #BDBDBD26",
          width: 350,
        }}
      >
        <h2 style={{ color: "#5D5FEF", textAlign: "center", marginBottom: 24 }}>
          Login
        </h2>
        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          style={inputStyle}
        />
        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          style={inputStyle}
        />
        <button
          type="submit"
          style={{
            background: "#5D5FEF",
            color: "#fff",
            borderRadius: 12,
            border: 0,
            padding: "10px",
            fontWeight: 600,
            fontSize: 16,
            width: "100%",
            marginTop: 14,
            cursor: "pointer",
          }}
        >
          Login
        </button>
        {error && <p style={{ color: "#C44737", marginTop: 14 }}>{error}</p>}
      </form>
    </div>
  );
}

const inputStyle = {
  width: "100%",
  padding: "10px 14px",
  borderRadius: 8,
  border: "1px solid #D1D8ED",
  fontSize: 16,
  margin: "14px 0 0 0",
  boxSizing: "border-box",
};
